class ValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "ValidationError";
  }
}

class DatabaseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = "DatabaseError";
  }
}

type Result<T> = { success: true; data: T } | { success: false; error: Error };

function fetchUser(id: number): Result<{ name: string }> {
  if (id <= 0) {
    return { success: false, error: new ValidationError("Invalid user ID") };
  }
  // Simulate fetching...
  return { success: true, data: { name: "John Doe" } };
}

const result = fetchUser(-1);

if (!result.success) {
  console.error(result.error.name + ': ' + result.error.message);
} else {
  console.log('User:', result.data.name);
}

type AppError = 
  | { type: "validation"; message: string }
  | { type: "database"; message: string };

function handleError(error: AppError) {
  switch (error.type) {
    case "validation":
      console.log(`Validation Error: ${error.message}`);
      break;
    case "database":
      console.log(`Database Error: ${error.message}`);
      break;
    default:
      // This ensures all error types are handled
      const _exhaustiveCheck: never = error;
      return _exhaustiveCheck;
  }
}

async function getData() {
  try {
    const data = await fetch('/api/data');
    if (!data.ok) {
      throw new DatabaseError('Failed to fetch data');
    }
    const json = await data.json();
    return json;
  } catch (error) {
    if (error instanceof ValidationError) {
      console.error('Validation issue:', error.message);
    } else if (error instanceof DatabaseError) {
      console.error('Database issue:', error.message);
    } else {
      console.error('Unknown error:', error);
    }
    throw error; // Rethrow or handle accordingly
  }
}

function logError(error: Error) {
  // Could integrate with a service like Sentry or LogRocket
  console.error(`[${error.name}] - ${error.message}`);
}

try {
  throw new ValidationError('Invalid input data');
} catch (error) {
  if (error instanceof Error) {
    logError(error);
  }
}

